/// <reference types="jest" />
import { RolesGuard } from './roles.guard';
import { Reflector } from '@nestjs/core';
import { ExecutionContext, ForbiddenException } from '@nestjs/common';
import { UserRole } from '../../users/enums/userRoles.enum';

describe('RolesGuard', () => {
  it('returns true when no roles required', () => {
    const reflector = { getAllAndOverride: jest.fn().mockReturnValue(undefined) } as unknown as Reflector;
    const guard = new RolesGuard(reflector);
    const context = { getHandler: () => {}, getClass: () => {}, switchToHttp: () => ({ getRequest: () => ({}) }) } as unknown as ExecutionContext;
    expect(guard.canActivate(context)).toBe(true);
  });

  it('throws when user not present', () => {
    const reflector = { getAllAndOverride: jest.fn().mockReturnValue([UserRole.USER]) } as unknown as Reflector;
    const guard = new RolesGuard(reflector);
    const context = { getHandler: () => {}, getClass: () => {}, switchToHttp: () => ({ getRequest: () => ({}) }) } as unknown as ExecutionContext;
    expect(() => guard.canActivate(context)).toThrow(ForbiddenException);
  });

  it('throws when user level insufficient', () => {
    const reflector = { getAllAndOverride: jest.fn().mockReturnValue([UserRole.ADMIN]) } as unknown as Reflector;
    const guard = new RolesGuard(reflector);
    const reqUser = { user: { role: UserRole.USER } };
    const context = { getHandler: () => {}, getClass: () => {}, switchToHttp: () => ({ getRequest: () => reqUser }) } as unknown as ExecutionContext;
    expect(() => guard.canActivate(context)).toThrow(ForbiddenException);
  });

  it('returns true when user has sufficient role', () => {
    const reflector = { getAllAndOverride: jest.fn().mockReturnValue([UserRole.USER]) } as unknown as Reflector;
    const guard = new RolesGuard(reflector);
    const reqUser = { user: { role: UserRole.SUPER_ADMIN } };
    const context = { getHandler: () => {}, getClass: () => {}, switchToHttp: () => ({ getRequest: () => reqUser }) } as unknown as ExecutionContext;
    expect(guard.canActivate(context)).toBe(true);
  });
});

